  /**
   * Get an entire config object. Returns config for the site when its ID is provided o generic config object instead.
   *
   * @param platform Optional Mercado Libre Platform ID
   * @param site Optional site Mercado Libre Site ID
   * @param environment When `environment` is provided config will look for the data associated with corresponding environment
   *
   * @returns Returns the entire config object
   *
   * @example
   * const conf = config.toJSON(); // Generic config object
   * const siteConf = config.toJSON('ML', 'MLA'); // Config for Mercado Libre Argentina
   */
  toJSON<T = unknown>(platform: PlatformId, site: SiteId, environment?: ConfigEnvironment): T;
  toJSON<T = unknown>(): T;

  /**
   * Update the config with a bunch of data
   *
   * @param data New data to include in config
   * @param checkVersion check version when updating config. Only newer config will be accepted if true
   */
